var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"밤 바다…… 바람은 좀 쌀쌀해도 꽤 나쁘지 않죠?","JPN":"夜の海……風は少し冷たいけど、なかなか悪くないだろう？","ENG":"The ocean at night... It might be a little chilly, but it’s not so bad, is it?","TWN":"晚上的海邊……雖然風有點涼，但還是很不錯對吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"서, 선생님?","JPN":"せ、先生？","ENG":"T-Teacher?!","TWN":"老…老師？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저는 오늘 같은 날이 아니면 쉽게 할 수 없는 이야기가 있다고 생각해요.","JPN":"今日のような日でないと、簡単に話せない話があるんじゃないかと思ってね。","ENG":"I think now is the perfect opportunity to talk about overlooked things.","TWN":"我覺得今天這種機會很難得，可以將平時不容易說出口的話說出來。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여행이 끝나고 다시 일상으로 돌아가면, 타이밍을 놓쳐서 쉽게 꺼낼 수 없는 이야기들…….","JPN":"旅行が終わってまた日常に戻ると、チャンスがなくてなかなかできない話とか……","ENG":"The things we don’t talk about once we go back to our daily lives...","TWN":"等旅行結束回到一般日常生活後，那些就很難說出口的話……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 저의 괜한 참견일 뿐일까요?","JPN":"はは、余計なお節介かな？","ENG":"Perhaps I’m being too nosy, ha ha.","TWN":"哈哈，是我太雞婆嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저라도 괜찮다면, 박스 군의 이야기를 들어보고 싶군요.","JPN":"私でもよければ、ダンボール君の話を聞いてみたいな。","ENG":"But if it’s fine with you, Box... I’d like to hear your story.","TWN":"不介意的話，我想聽聽你的故事。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 사실…… 학교를 다니지 않아요.","JPN":"僕、実は……学校に通ってません。","ENG":"To be frank... I don’t go to school.","TWN":"其實我……沒有在上學。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"등교 거부…… 하고 있거든요.","JPN":"不登校……なんです。","ENG":"I’m... refusing, to be exact.","TWN":"我……拒絕上學。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나들이랑 게임을 만들 수 있었던 것도……","JPN":"みんなでゲームを作るのも……","ENG":"The reason why I was able to join the club...","TWN":"所以我才可以和姊姊們一起做遊戲……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"동아리 방에서 철야를 할 수 있었던 것도…… 그래서 가능했던 거고요.","JPN":"部室で徹夜するのも……だからできたんです。","ENG":"And the reason why I was able to pull all-nighters at the club room... was because of that.","TWN":"還可以在社辦熬夜……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이유를 물어봐도 될까요?","JPN":"理由を聞いてもいいかな？","ENG":"May I ask why?","TWN":"我可以問你理由嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"간단해요. 제 얼굴, 여자애처럼 생겼거든요.","JPN":"簡単です。僕の顔、女の子みたいですから。","ENG":"It’s simple. Because I look too feminine.","TWN":"理由很簡單，因為我長得像女生。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"한심하죠? 고작 이런 이유로……","JPN":"情けないでしょう？　たかがこんな理由で……","ENG":"Pathetic, isn’t it? I cower over nothing...","TWN":"很糟糕對吧？因為這個理由就……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하지만 고작 이런 이유로 반 애들한테 꽤 오랫동안 따돌림당했어요.","JPN":"でも、たかがこんな理由でクラスメイトにかなり長い間いじめられたんです。","ENG":"But because of this irrelevant issue, I was bullied in school for a long time.","TWN":"但因為這個理由，我長期受到班上同學的排擠。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 샐러리맨X의 마스크를…….","JPN":"それでサラリーマンXのマスクを……","ENG":"Hence the Salaryman X mask...","TWN":"所以你才會戴著上班族X的面具……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네. 샐러리맨X는 저한테 용기를 주거든요. 사실 이렇게 선생님과 평범하게 대화를 나눌 수 있는 것도 이 마스크 덕분이에요.","JPN":"はい。サラリーマンXは僕に勇気をくれるんです。実はこうやって先生と普通に話せるのも、このマスクのおかげなんです。","ENG":"Yes. Salaryman X gives me strength. This mask is the sole reason I'm able to talk like this with you, Teacher.","TWN":"沒錯，是上班族X給我勇氣的，現在能夠像這樣和老師正常聊天，也是因為有這個面具。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하핫, 이상하죠? 마스크가 없으면 말도 잘 못한다는 거……?","JPN":"ははっ、おかしいでしょう？　マスクがないとちゃんと話もできないなんて……","ENG":"Ha ha, I know it sounds strange. Being unable to talk without putting a mask on...","TWN":"哈哈，很詭異吧？竟然沒戴面具就沒辦法說話……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"다른 사람들도 그렇더라고요. 그냥 이상한 박스를 뒤집어쓴 이상한 놈일뿐이죠.","JPN":"他の人たちもそんな感じでした。ただ変なダンボールを被ってる変なやつだって。","ENG":"People say that all the time. To them, I’m a freak with a cardboard box on his head.","TWN":"其他人也都說我是戴著奇怪紙箱的怪人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그렇지만 누나들은 달랐어요.","JPN":"でも、ここのみんなはそうじゃなかった。","ENG":"But you guys are different.","TWN":"可是姊姊們不會。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"코미페에서 처음 본 뒤로 지금까지 단 한 번도 왜 이런 걸 쓰고 다니는 지 묻지 않았죠.","JPN":"コミフェで初めて会った時から今まで、だだの一度もなんでこんなものを被ってるのか聞きませんでした。","ENG":"Not a single person in the club asked about my mask, not even once.","TWN":"在動漫展第一次見面到現在，她們從來沒問過我為何要戴著這個。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"제 맨 얼굴을 본 뒤에도…….","JPN":"僕の素顔を見た後も……","ENG":"Even after you saw my bare face...","TWN":"甚至在看到我的真面目後也是……"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가면을 쓰는 건 이상한 일이 아닙니다.","JPN":"仮面を被るのはおかしなことじゃないよ。","ENG":"No one should be condemned for wearing masks.","TWN":"戴面具不是什麼怪事，"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람은 누구나 저마다 말 못할 사정이 있는 법이니까요.","JPN":"誰でも、それぞれに人には言えない事情を抱えてるものだからね。","ENG":"We all have our own stories to tell.","TWN":"就像每個人都有不能說的秘密一樣，"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 학교에 남아 있는 사람들은 특히나 말입니다.","JPN":"この学校に残っている人たちは特に。","ENG":"Especially the ones left at this school.","TWN":"尤其是這間學校裡的人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군도, 저희 학생들도…… 그리고 저조차도 말이죠.","JPN":"ダンボール君も、私の生徒たちも……そして私もね。","ENG":"That includes you, my students... and even myself.","TWN":"無論是你，或是我的學生們……還是我，大家都一樣。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네. 알고 있어요. 하지만……","JPN":"はい。わかってます。でも……","ENG":"Yes, I know. But somehow...","TWN":"是的，我知道，但是……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하지만 카운터즈 사가를 완성하고 나면…… 어째선지 더는 누나들을 만나지 못할 것 같은 느낌이 들어요.","JPN":"でも、カウンターズ・サーガが完成すれば……どうしてか、もうみんなに会えなくなりそうな気がするんです。","ENG":"Somehow... I feel like I won’t be able to see you all anymore once we’re finished with Counters Saga.","TWN":"但是我總覺得，等到制裁者傳奇完成後……好像就再也見不到她們似的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"애초에 저랑 누나들은…… 사는 세계부터가 다르니까.","JPN":"そもそも僕とみんなは……住む世界が違いますから。","ENG":"We live in different worlds, you know...","TWN":"或許是因為，我和她們……打從一開始就是不同世界的人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"박스 군, 미래라는 건 아무도 알 수 없습니다.","JPN":"ダンボール君、未来というのは誰にもわからないものなんだ。","ENG":"No one knows what the future holds, Box.","TWN":"紙箱小朋友，未來的事誰也不知道。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 오히려 알 수 없기에 인간은 지금 이 순간에 충실해야 하죠.","JPN":"いや、むしろわからないからこそ、人間は今この瞬間を精一杯生きないといけないんだ。","ENG":"Which is why we need to focus on the present.","TWN":"應該是說，正是因為不知道，人們才更應該活在當下。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금은 부질없어 보이는 작은 노력일지라도……","JPN":"今は無駄に見える小さな努力であっても……","ENG":"What might look like a useless act now...","TWN":"或許現在是看似毫無意義的努力……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 싹이 되어서 먼 미래의 어떤 결과를 바꿔 놓을 수도 있으니까요.","JPN":"それが芽生えて、遠い未来のある結果を変えることもあるからね。","ENG":"...Might grow into something powerful enough to change fate.","TWN":"但未來都有可能會萌芽長成某種結果。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건…… 이 세상 그 누구보다도 제가 가장 잘 알고 있습니다.","JPN":"それは……この世の誰よりも、私が一番よくわかっている。","ENG":"Trust me... I know more than anyone else in this world.","TWN":"這一點……我比世界上任何一個人都還要清楚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네? 그게 무슨 말이에요?","JPN":"え？　それはどういう意味ですか？","ENG":"Huh? What do you mean?","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아이들에게 신세 지는 처지로서 떠올릴 만한 변명이죠.","JPN":"子どもたちにお世話になっている身として考えそうな言い訳だよ。","ENG":"It’s an excuse I make, seeing how I rely on the girls so much.","TWN":"這是因為我欠她們太多，所以替自己找的藉口。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니, 지금의 카운터즈 사가는 박스 군이 원했던 게임이 되었나요?","JPN":"そういえば、今のカウンターズ・サーガはダンボール君が望んでいたとおりのゲームになったかな？","ENG":"Come to think of it, has Counters Saga become a good enough game for you?","TWN":"話說回來，現在的制裁者傳奇有成為你想要的遊戲嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네? 갑자기 그건 왜…….","JPN":"え？　急にどうしてそんなことを……","ENG":"Huh? Why do you ask, all of a sudden...?","TWN":"嗯？怎麼突然這麼問……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지 않다면 혹시 지금 박스 군이 가장 바라는 건 뭔가요?","JPN":"もし違うとしたら、今ダンボール君が一番やりたいことは何だろうか。","ENG":"If not, what do you want to add most?","TWN":"不是的話，那你現在最想要的是什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"제가 지금 바라는 것……?","JPN":"僕が今やりたいこと……？","ENG":"What I want most...?","TWN":"我現在最想要的……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"네. 그걸 게임에 구현한다면, 아무리 시간이 지난다고 해도 지금의 경험이……","JPN":"そう。それをゲームの中で具現化すれば、どれだけ時間が経っても今の経験が……","ENG":"Yes. If we take that into the game, perhaps this moment, our time together...","TWN":"對，將它放到遊戲裡，那無論經過多久的時間，現在的經驗……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 이 순간이, 박스 군에게 조금 더 각별하게 남을 수 있지 않을까요?","JPN":"今この瞬間が、ダンボール君にとってもっと特別なものとして残るんじゃないかな。","ENG":"It might be remembered as something very dear to you, no matter how much time pass.","TWN":"現在這個瞬間，都會成為你最特別的回憶吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 저는……","JPN":"ぼ、僕は……","ENG":"I-I...","TWN":"我現在……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"왔구나…… 박스.","JPN":"来たんだね……ダンボール君。","ENG":"Here... you are. Boxie.","TWN":"來啦……紙箱。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……네.","JPN":"……はい。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"들었어……. 선생님한테.","JPN":"聞いた……先生から。","ENG":"From Teacher... I heard.","TWN":"老師……有跟我說。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"넣고 싶다면서……? 다른 애들 모르게.","JPN":"入れたいんだって……？　他の二人には内緒で。","ENG":"You want to put it in... secretly.","TWN":"瞞著其他人……加東西？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>이스터 에그</color>.","JPN":"……<color=#ffd34c>イースターエッグ</color>。","ENG":"...<color=#ffd34c>Easter eggs</color>.","TWN":"……<color=#ffd34c>彩蛋</color>。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네, 특정 조건에서 특정 키워드를 입력하면 이스터에그가 발동하게끔 할 수 있을까요?","JPN":"はい、特定の条件で特定のキーワードを入力すると、イースターエッグが発動するようにできますか？","ENG":"Yes, do you think we could activate them when certain keywords are typed in at certain conditions?","TWN":"是的，在特定條件下輸入特定的關鍵字，就會觸發彩蛋。這姊姊做得到嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 가능해…… 아마도.","JPN":"うん。できる……たぶん。","ENG":"Possible... probably. Yes.","TWN":"嗯，可以……應該。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하지만 오늘까지야.","JPN":"でも今日まで。","ENG":"But it should be done today.","TWN":"不過今天是最後一天。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보내야 하니까……. 발주.","JPN":"送らないと……発注。","ENG":"The order... we need to place.","TWN":"必須……下單。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"상관없어요.","JPN":"構いませんよ。","ENG":"It doesn’t matter.","TWN":"沒問題，"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"리소스…… 전부 준비해왔으니까.","JPN":"リソース……全部準備してきたんで。","ENG":"All of the resources... are prepared.","TWN":"素材……我都準備好了。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};